lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;floor&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;Math&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;random&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;200&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;372&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;373&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token comment&#34;&gt;// 随机动画延迟（0-6 秒），出现更错落&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;374&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                bubble&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;style&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;animationDelay &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token template-string&#34;&gt;&lt;span class=&#34;token template-punctuation string&#34;&gt;`&lt;/span&gt;&lt;span class=&#34;token interpolation&#34;&gt;&lt;span class=&#34;token interpolation-punctuation punctuation&#34;&gt;$&amp;#123;&lt;/span&gt;Math&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;random&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;6&lt;/span&gt;&lt;span class=&#34;token interpolation-punctuation punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;s&lt;/span&gt;&lt;span class=&#34;token template-punctuation string&#34;&gt;`&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;375&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;376&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                resultDiv&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;appendChild&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;bubble&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;377&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;378&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token comment&#34;&gt;// 7 秒后移除气泡（与动画周期一致）&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;379&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token function&#34;&gt;setTimeout&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;=&gt;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;380&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                    bubble&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;remove&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;381&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;7000&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;382&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;383&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;384&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token comment&#34;&gt;// 清除旧定时器&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;385&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;if&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;bubbleInterval&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;clearInterval&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;bubbleInterval&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;386&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;387&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token comment&#34;&gt;// 调整生成节奏：初始 65 个，每 0.12 秒生成 1 个（更密集但不拥挤）&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;388&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token keyword&#34;&gt;for&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token keyword&#34;&gt;let&lt;/span&gt; i &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; i &lt;span class=&#34;token operator&#34;&gt;&amp;lt;&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;65&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt; i&lt;span class=&#34;token operator&#34;&gt;++&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;createRandomBubble&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;389&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            bubbleInterval &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;setInterval&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;createRandomBubble&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;120&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;390&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;391&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            &lt;span class=&#34;token function&#34;&gt;hideAllSteps&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;392&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;            resultDiv&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;classList&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;&lt;span class=&#34;token function&#34;&gt;remove&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token string&#34;&gt;&#39;hidden&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;393&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;394&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;script&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;395&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;body&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;396&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;html&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

 &lt;h1 id=&#34;茗叙&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#茗叙&#34;&gt;#&lt;/a&gt; 茗叙&lt;/h1&gt;
&lt;p&gt;我已经开学补课两周了，这个期间我发现我有太多的问题，与一些感受，高三的生活想过得好肯定不可能的，那么我既然选择了走下去，那我该如何走下去，人人都想上一个好大学，那我如何比别人更优秀？可以分享下你的经验，欢迎志同道合的人来交流！&lt;/p&gt;
&lt;h1 id=&#34;茗述&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#茗述&#34;&gt;#&lt;/a&gt; 茗述&lt;/h1&gt;
&lt;h2 id=&#34;我的上课状态&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#我的上课状态&#34;&gt;#&lt;/a&gt; 我的上课状态&lt;/h2&gt;
&lt;p&gt;由于刚经历暑假的都知道，都想窝在家里玩，一个月也没动脑子里，既然如何，远离了舒适区肯定不太舒服，上课犯困，注意力不集中也是如此，我注意力不集中总是会想到别的无关紧要的事情，在数学和物理课上很严重。由于两个可不确实不是很好，有时候也确实没听懂，但是又觉得自己好像又能琢磨出来，物理该不会的确实不会，老师以习题讲解，随后再补充公式，就这样听，但我感觉别人在做题，而我脑中没有一点思路，还是看别人写的推测在写什么，用哪个公式才勉强跟得上.&lt;/p&gt;
&lt;p&gt;还有便是数学，这个我真的很头疼，第一次写作业我发现有些题跟讲的不一样，讲的太简单了，自己做怎么这么难，之后也是没思路，但是别人能做出来 (我同桌呜呜), 人家还是少数名族，而我每次看了她的才发现，原来要这样做，当自己做的时候是真的脑中空白，我看着讲义，按照讲义的概念与方法算的，但还是没什么思路，这可能就是需要老师在讲完讲义之后需要自己琢磨一下，自己尝试做一遍，而我高一二就没有养成这种习惯，之后自己不会老师一讲我就会。在生物上高考真的很玄乎，四个选项几乎都是对的，但是老师讲的时候回补充知识盲区，这个该如何去记忆呢？书上与讲义上根本没写，而我也确实不知道，分散着记忆肯定记不全，每个单元都有不同的新知识，所以高三第一轮复习，是在复习还是在补新？&lt;/p&gt;
&lt;h2 id=&#34;在我空余时间&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#在我空余时间&#34;&gt;#&lt;/a&gt; 在我空余时间&lt;/h2&gt;
&lt;p&gt;学校不管是语文还是英语，生物还是化学，都有要背的内容，但是时间就这么多我该怎么去安排很重要，语文比较简单，但是工作量很大，英语很难，但背的单词很少，生物和化学都是零碎的小点，上课时候就能记忆，可下次如果在遇到就不知道会不会做，还有作业这个很苦难，有时候到中午老师都没有布置作业，虽然每天就写 4 课，但是总不能全部堆积到晚自习写着肯定时间来不及的，既然如此我想的是课间可以整理一下数学是习题，自己做一做，或者英语阅读写一篇，课间就十分钟，有时候不到三个题就上课了，让后就是短暂的缺氧，我站到后面听，每天很累，但害怕它不出效果，我所有科目就英语跟物理不行，这该怎么学？&lt;/p&gt;
&lt;h2 id=&#34;英语是个大问题&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#英语是个大问题&#34;&gt;#&lt;/a&gt; 英语是个大问题&lt;/h2&gt;
&lt;p&gt;我的英语一直是个谜，你要说语法其实我也会，你要说单词，部分我也认识，但是做起来怎么这么难？我小学英语就很好，说明我底子还不错的，初中除了没背多少单词，但是语法我都习得，以上了高中我阅读题就没有全队过，高一二换了很多学习方法，但都不太行，不知道是我自己没有坚持下去，还是什么，总之会出现各种问题的。有时候蒙的全队，自己做的全错，没错就是这样，你要说阅读，单词我能看懂，10 个能看 7 个，但是练不成一个句子，很苦难，而且英语 书上单词我都认真背了，但还是记不住单词，单词这方面班主任抓得很严，所以我没有亏待自己过，背了写，写了改，就是这样，英语书上每次单词我绝对没亏待过，但是当我拿起 3500 的时候，发现这个不认识，哪个也是，而我舍友轻松就回答，怪不得人家是第一。这究竟 该如何学呢？&lt;/p&gt;
&lt;h2 id=&#34;宿舍这方面&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#宿舍这方面&#34;&gt;#&lt;/a&gt; 宿舍这方面&lt;/h2&gt;
&lt;p&gt;我是住宿的，只有周天一天能待，之后就下午六点就想着要走了.&lt;/p&gt;
&lt;p&gt;新来的第二周就换了新的宿舍，我与之间住了三个学期的舍友说再见了，在这个新的宿舍，环境挺好，人少，也没什么怪问题，但是我发现，我这个睡眠圣体竟然睡不着？？我刚搬到新宿舍我就说，放心吧我一躺下就睡着。结果就在这周五，死活睡不着，我估么着起码晚上 3 点了，我还是没睡着，我用了我之前更新的睡眠方法还是不起作用，每次都想睡着了但是蚊子来了，你这怎么说？晚上都是浅睡，哎，买了个蚊香不知效果如何，希望我能好好睡一觉吧呜呜！&lt;/p&gt;
&lt;p&gt;先到这吧，其他的下周在更新.....&lt;/p&gt;
&lt;p&gt;有什么好的意见或者方法记得告诉我 oWo~~&lt;/p&gt;

 &lt;h1 id=&#34;茗叙&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#茗叙&#34;&gt;#&lt;/a&gt; 茗叙&lt;/h1&gt;
&lt;p&gt;这段时间消失了快一个月了，简直要命！&lt;/p&gt;
&lt;p&gt;放假之后就报考了驾校就开始 练车，前几天天天刷题，最终也是合格，现在科目二练习，倒车入库时练习的最快的！坡位定点也是轻轻松松，每天练车两个小时，这大太阳！我真的服了！每天出门就两个小时，这都能把我晒黑了，哎怎么办呢，又得一个冬天熬白了，呜呜呜！&lt;/p&gt;
&lt;p&gt;这几月就是在赚钱，也不是去打工，就是自己搞一点网赚，也是有了一点点收益还不错，我自己平时就自己做菜用而已，也没什么花钱的地方，主要我的 &lt;code&gt;女性朋友&lt;/code&gt; ，她在米东区实习，在医院，谁能想实习竟然没有工资，每天都不知道能不能吃饱，每天就吃点泡面，真的挺担心她的，可惜我们相隔挺远的。前天她还说她变了，我还以为她说我们关系疏远了，谁知她说她 &lt;code&gt;有点消瘦&lt;/code&gt; 了，也确实又回到了高压的环境工作，谁都有一点疲劳吧，再加上又没有休息好，确实有一点！请求各位能否资助她一点点用来吃饭，我自己挣的钱她是不想收，说这是我的钱要收好，每次都劝了好久才收下，但我这钱也不够她吃一周的，她还要工作八个月，到时候我上学就确实没人资助她，也挺可怜的.(&lt;strong&gt;最下方点击赞助就行！&lt;/strong&gt;) 感谢各位了！&lt;/p&gt;
&lt;p&gt;好了我们聊正事！&lt;/p&gt;
&lt;p&gt;这是一期影视资源的网站搭建，内置了 api 接口可以直接收看影视！&lt;/p&gt;
&lt;h1 id=&#34;茗述&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#茗述&#34;&gt;#&lt;/a&gt; 茗述&lt;/h1&gt;
&lt;h2 id=&#34;1首先我们要准备账号&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1首先我们要准备账号&#34;&gt;#&lt;/a&gt; 1. 首先我们要准备账号&lt;/h2&gt;
&lt;p&gt;一个&lt;a href=&#34;https://github.com&#34;&gt; Github&lt;/a&gt; 账号&lt;/p&gt;
&lt;p&gt;一个&lt;a href=&#34;https://cloudflare.com&#34;&gt; Cloudflare&lt;/a&gt; 账号&lt;/p&gt;
&lt;p&gt;首先 fork 下面的项目&lt;/p&gt;
&lt;p&gt;LibreTV:**&lt;a href=&#34;https://github.com/LibreSpark/LibreTV&#34;&gt;https://github.com/LibreSpark/LibreTV&lt;/a&gt; **&lt;/p&gt;
&lt;p&gt;或者这里有一键式部署:&lt;/p&gt;
&lt;p&gt;选择以下任一平台，点击一键部署按钮，即可快速创建自己的 LibreTV 实例：&lt;/p&gt;
&lt;p&gt;&lt;a href=&#34;https://vercel.com/new/clone?repository-url=https%3A%2F%2Fgithub.com%2FLibreSpark%2FLibreTV&#34;&gt;Deploy with Vercel&lt;/a&gt;&lt;br&gt;
&lt;a href=&#34;https://app.netlify.com/start/deploy?repository=https://github.com/LibreSpark/LibreTV&#34;&gt;Deploy to Netlify&lt;/a&gt;&lt;br&gt;
&lt;a href=&#34;https://render.com/deploy?repo=https://github.com/LibreSpark/LibreTV&#34;&gt;Deploy to Render&lt;/a&gt;&lt;br&gt;
&lt;a href=&#34;https://edgeone.ai/pages/new?repository-url=https://github.com/LibreSpark/LibreTV&#34;&gt; 使用 EdgeOne Pages 部署&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;下面是官方配的教程，这里只放我的图，只用 cloudflare 演示&lt;/p&gt;
&lt;h2 id=&#34;详细部署指南&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#详细部署指南&#34;&gt;#&lt;/a&gt; 详细部署指南&lt;/h2&gt;
&lt;h3 id=&#34;cloudflare-pages&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#cloudflare-pages&#34;&gt;#&lt;/a&gt; Cloudflare Pages&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;Fork 或克隆本仓库到您的 GitHub 账户&lt;/li&gt;
&lt;li&gt;登录 &lt;a href=&#34;https://dash.cloudflare.com/&#34;&gt;Cloudflare Dashboard&lt;/a&gt;，进入 Pages 服务&lt;/li&gt;
&lt;li&gt;点击 &amp;quot;创建项目&amp;quot;，连接您的 GitHub 仓库&lt;img loading=&#34;lazy&#34; data-src=&#34;LibreTV/image-20250721200004012.png&#34; alt=&#34;image-20250721200004012&#34;&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;LibreTV/image-20250721200032775.png&#34; alt=&#34;image-20250721200032775&#34;&gt;&lt;/li&gt;
&lt;li&gt;使用以下设置：
&lt;ul&gt;
&lt;li&gt;构建命令：留空（无需构建）&lt;/li&gt;
&lt;li&gt;输出目录：留空（默认为根目录）&lt;/li&gt;
&lt;li&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/2025/07/21/LibreTV/image-20250721200058801.png&#34; class title=&#34;image-20250721200058801&#34;&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;⚠️ 重要：在 &amp;quot;设置&amp;quot; &amp;gt; &amp;quot;环境变量&amp;quot; 中添加  &lt;code&gt;PASSWORD&lt;/code&gt;  变量&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;可选：在 &amp;quot;Settings&amp;quot; &amp;gt; &amp;quot;Environment Variables&amp;quot; 中添加  &lt;code&gt;ADMINPASSWORD&lt;/code&gt;  变量&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;点击 &amp;quot;保存并部署&amp;quot;&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;如下展示: &lt;a href=&#34;http://tv.mingcy.cn&#34;&gt;tv.mingcy.cn&lt;/a&gt;&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/2025/07/21/LibreTV/image-20250721200629334.png&#34; class title=&#34;image-20250721200629334&#34;&gt;&lt;/p&gt;
&lt;h3 id=&#34;vercel&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#vercel&#34;&gt;#&lt;/a&gt; Vercel&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;Fork 或克隆本仓库到您的 GitHub/GitLab 账户&lt;/li&gt;
&lt;li&gt;登录 &lt;a href=&#34;https://vercel.com/&#34;&gt;Vercel&lt;/a&gt;，点击 &amp;quot;New Project&amp;quot;&lt;/li&gt;
&lt;li&gt;导入您的仓库，使用默认设置&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;⚠️ 重要：在 &amp;quot;Settings&amp;quot; &amp;gt; &amp;quot;Environment Variables&amp;quot; 中添加  &lt;code&gt;PASSWORD&lt;/code&gt;  变量&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;可选：在 &amp;quot;Settings&amp;quot; &amp;gt; &amp;quot;Environment Variables&amp;quot; 中添加  &lt;code&gt;ADMINPASSWORD&lt;/code&gt;  变量&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;点击 &amp;quot;Deploy&amp;quot;&lt;/li&gt;
&lt;li&gt;可选：在 &amp;quot;Settings&amp;quot; &amp;gt; &amp;quot;Environment Variables&amp;quot; 中配置密码保护和设置按钮密码保护&lt;/li&gt;
&lt;/ol&gt;
&lt;h3 id=&#34;render&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#render&#34;&gt;#&lt;/a&gt; Render&lt;/h3&gt;
&lt;ol&gt;
&lt;li&gt;Fork 或克隆本仓库到您的 GitHub 账户&lt;/li&gt;
&lt;li&gt;登录 &lt;a href=&#34;https://render.com/&#34;&gt;Render&lt;/a&gt;，点击 &amp;quot;New Web Service&amp;quot;&lt;/li&gt;
&lt;li&gt;选择您的仓库，Render 会自动检测到  &lt;code&gt;render.yaml&lt;/code&gt;  配置文件&lt;/li&gt;
&lt;li&gt;保持默认设置（无需设置环境变量，默认不启用密码保护）&lt;/li&gt;
&lt;li&gt;点击 &amp;quot;Create Web Service&amp;quot;，等待部署完成&lt;/li&gt;
&lt;li&gt;部署成功后即可访问您的 LibreTV 实例&lt;/li&gt;
&lt;/ol&gt;
&lt;blockquote&gt;
&lt;p&gt;如需启用密码保护，可在 Render 控制台的环境变量中手动添加  &lt;code&gt;PASSWORD&lt;/code&gt;  和 / 或  &lt;code&gt;ADMINPASSWORD&lt;/code&gt; 。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;docker&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#docker&#34;&gt;#&lt;/a&gt; Docker&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;docker run -d \
  --name libretv \
  --restart unless-stopped \
  -p 8899:8080 \
  -e PASSWORD=your_password \
  -e ADMINPASSWORD=your_adminpassword \
  bestzwei/libretv:latest
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;docker-compose&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#docker-compose&#34;&gt;#&lt;/a&gt; Docker Compose&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;docker-compose.yml&lt;/code&gt;  文件：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;services:
  libretv:
    image: bestzwei/libretv:latest
    container_name: libretv
    ports:
      - &amp;quot;8899:8080&amp;quot; # 将内部 8080 端口映射到主机的 8899 端口
    environment:
      - PASSWORD=$&amp;#123;PASSWORD:-your_password&amp;#125; # 可将 your_password 修改为你想要的密码，默认为 your_password
      - ADMINPASSWORD=$&amp;#123;PASSWORD:-your_adminpassword&amp;#125; # 可将 your_adminpassword 修改为你想要的密码，默认为 your_adminpassword
    restart: unless-stopped
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;启动 LibreTV：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;docker compose up -d
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;访问  &lt;code&gt;http://localhost:8899&lt;/code&gt;  即可使用。&lt;/p&gt;
&lt;h3 id=&#34;本地开发环境&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#本地开发环境&#34;&gt;#&lt;/a&gt; 本地开发环境&lt;/h3&gt;
&lt;p&gt;项目包含后端代理功能，需要支持服务器端功能的环境：&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;# 首先，通过复制示例来设置 .env 文件（可选）
cp .env.example .env

# 安装依赖
npm install

# 启动开发服务器
npm run dev
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;访问  &lt;code&gt;http://localhost:8080&lt;/code&gt;  即可使用（端口可在.env 文件中通过 PORT 变量修改）。&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;⚠️ 注意：使用简单静态服务器（如  &lt;code&gt;python -m http.server&lt;/code&gt;  或  &lt;code&gt;npx http-server&lt;/code&gt; ）时，视频代理功能将不可用，视频无法正常播放。完整功能测试请使用 Node.js 开发服务器。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;自定义配置&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#自定义配置&#34;&gt;#&lt;/a&gt; 🔧 自定义配置&lt;/h2&gt;
&lt;h3 id=&#34;密码保护&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#密码保护&#34;&gt;#&lt;/a&gt; 密码保护&lt;/h3&gt;
&lt;p&gt;要为您的 LibreTV 实例添加密码保护，可以在部署平台上设置环境变量：&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;环境变量名&lt;/strong&gt;:  &lt;code&gt;PASSWORD&lt;/code&gt;  &lt;strong&gt;值&lt;/strong&gt;：您想设置的密码&lt;/p&gt;
&lt;p&gt;&lt;strong&gt;环境变量名&lt;/strong&gt;:  &lt;code&gt;ADMINPASSWORD&lt;/code&gt;  &lt;strong&gt;值&lt;/strong&gt;：您想设置的密码&lt;/p&gt;
&lt;p&gt;各平台设置方法：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;Cloudflare Pages&lt;/strong&gt;: Dashboard &amp;gt; 您的项目 &amp;gt; 设置 &amp;gt; 环境变量&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Vercel&lt;/strong&gt;: Dashboard &amp;gt; 您的项目 &amp;gt; Settings &amp;gt; Environment Variables&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Netlify&lt;/strong&gt;: Dashboard &amp;gt; 您的项目 &amp;gt; Site settings &amp;gt; Build &amp;amp; deploy &amp;gt; Environment&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Docker&lt;/strong&gt;: 修改  &lt;code&gt;docker run&lt;/code&gt;  中  &lt;code&gt;your_password&lt;/code&gt;  为你的密码&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Docker Compose&lt;/strong&gt;: 修改  &lt;code&gt;docker-compose.yml&lt;/code&gt;  中的  &lt;code&gt;your_password&lt;/code&gt;  为你的密码&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;本地开发&lt;/strong&gt;: SET PASSWORD=your_password&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;api兼容性&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#api兼容性&#34;&gt;#&lt;/a&gt; API 兼容性&lt;/h3&gt;
&lt;p&gt;LibreTV 支持标准的苹果 CMS V10 API 格式。添加自定义 API 时需遵循以下格式：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;搜索接口:  &lt;code&gt;https://example.com/api.php/provide/vod/?ac=videolist&amp;amp;wd=关键词&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;详情接口:  &lt;code&gt;https://example.com/api.php/provide/vod/?ac=detail&amp;amp;ids=视频ID&lt;/code&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;strong&gt;添加 CMS 源&lt;/strong&gt;:&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;在设置面板中选择 &amp;quot;自定义接口&amp;quot;&lt;/li&gt;
&lt;li&gt;接口地址:  &lt;code&gt;https://example.com/api.php/provide/vod&lt;/code&gt;&lt;/li&gt;
&lt;/ol&gt;

 &lt;h1 id=&#34;茗起&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#茗起&#34;&gt;#&lt;/a&gt; 茗起&lt;/h1&gt;
&lt;p&gt;确实没更新了，半个月多了都，因为最近要期末考，涉及分班和数学学考，压力很大！&lt;/p&gt;
&lt;p&gt;有没有跟我一样的，喜欢把图片放在图床，但是又担心他会泄露！担心跑路，担心访问速度，担心过期等等什么..&lt;/p&gt;
&lt;p&gt;总的来说，就是不安全，那我能不能自我搭建一个呢，并且不要服务器！&lt;/p&gt;
&lt;p&gt;答案是显而易见的，今天为你带来 Vercel 搭建超快轻量的 BLOB&lt;/p&gt;
&lt;h1 id=&#34;茗述&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#茗述&#34;&gt;#&lt;/a&gt; 茗述&lt;/h1&gt;
&lt;h2 id=&#34;简单介绍一下这个项目&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#简单介绍一下这个项目&#34;&gt;#&lt;/a&gt; 简单介绍一下这个项目&lt;/h2&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th style=&#34;text-align:left&#34;&gt;项目&lt;/th&gt;
&lt;th style=&#34;text-align:left&#34;&gt;数据库大小&lt;/th&gt;
&lt;th style=&#34;text-align:left&#34;&gt;读&lt;/th&gt;
&lt;th style=&#34;text-align:left&#34;&gt;写&lt;/th&gt;
&lt;th style=&#34;text-align:left&#34;&gt;请求数&lt;/th&gt;
&lt;th style=&#34;text-align:left&#34;&gt;请求时长&lt;/th&gt;
&lt;th style=&#34;text-align:left&#34;&gt;是否需要 Projects&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td style=&#34;text-align:left&#34;&gt;Hobby&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;250MB / 月&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;1 亿 / 月&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;1 亿 / 月&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;1 亿 / 月&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;1 小时 / 月&lt;/td&gt;
&lt;td style=&#34;text-align:left&#34;&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/2025/06/02/blob/white_check_mark.png&#34; class title=&#34;:white_check_mark:&#34;&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;blockquote&gt;
&lt;p&gt;是不是很简单，哈哈哈😂😂&lt;/p&gt;
&lt;p&gt;看一下我的成品:&lt;img loading=&#34;lazy&#34; data-src=&#34;/2025/06/02/blob/image-20250602142812182.webp&#34; class title=&#34;image-20250602142812182&#34;&gt;&lt;/p&gt;
&lt;p&gt;** 因为只有 10GB, 故不开放我的图床了，大家自己搭建咯 **&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;做法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#做法&#34;&gt;#&lt;/a&gt; 做法&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;准备一个 Vercel 账号，可以直接使用 Github 登录&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;创建存储库（点击快速创建）：&lt;a href=&#34;https://vercel.com/new/clone?demo-description=SimpleNext.js%20template%20that%20uses%20Vercel%20Blob%20for%20image%20uploads&amp;amp;demo-image=%2F%2Fimages.ctfassets.net%2Fe5382hct74si%2FW7szxXAHpF3eZ4RFT33Cb%2F4d8a64904b67980e449b487089dd7b2b%2Fopengraph-image.webp&amp;amp;demo-title=Vercel%20Blob%20Next.js%20Starter&amp;amp;demo-url=https%3A%2F%2Fblob-starter.vercel.app%2F&amp;amp;project-name=blob-starter&amp;amp;repository-name=blob-starter&amp;amp;repository-url=https%3A%2F%2Fgithub.com%2Fvercel%2Fexamples%2Ftree%2Fmain%2Fstorage%2Fblob-starter&amp;amp;stores=%5B%7B%22type%22%3A%22blob%22%7D%5D&amp;amp;teamSlug=mc-sep-vercel-team&#34;&gt;Create&lt;/a&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;在接下来的页面中，名称自己填写，然后添加一个 Blob Store，确定即可&lt;/p&gt;
&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/2025/06/02/blob/2761ad503761d3dcb0ee11f10ed5818592f7b02f.webp&#34; class title=&#34;该图片显示了一个创建私有 Git 仓库和添加存储的 Vercel 界面截图，其中包括仓库名称、Git 范围和 Blob 存储选项。&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;pre&gt;&lt;code&gt;注意：每个用户只允许创建一个 Vercel Blob Storage！
&lt;/code&gt;&lt;/pre&gt;
&lt;ol start=&#34;4&#34;&gt;
&lt;li&gt;直到出现庆祝动画，点击 &lt;strong&gt;Continue to Dashboard&lt;/strong&gt;。&lt;/li&gt;
&lt;li&gt;点击 &lt;strong&gt;Settings → Environment Variables&lt;/strong&gt;，在最下方找到名为  &lt;code&gt;BLOB_READ_WRITE_TOKEN&lt;/code&gt;  的环境变量，点击复制，格式如下：&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;figcaption data-lang=&#34;plaintext&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;vercel_blob_rw_*************************************&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;&lt;img loading=&#34;lazy&#34; data-src=&#34;/2025/06/02/blob/96587f2115b71e80d9be35c9af9a19567bf0af0a_2_519x499.webp&#34; class title=&#34;该图片显示了一个应用程序的设置界面，用户可以在这里管理环境变量，包括添加、导入和查看共享环境变量。(由 AI 生成标题)&#34;&gt;&lt;/p&gt;
&lt;ol start=&#34;6&#34;&gt;
&lt;li&gt;
&lt;p&gt;返回 &lt;strong&gt;Settings → Functions&lt;/strong&gt;，将区域更改为 Hong Kong (East) – hkg1 或 Tokyo, Japan (Northeast) – hnd1&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;主要就是为了加速，还会香港快一点，日本，朝鲜的也能选.&lt;img loading=&#34;lazy&#34; data-src=&#34;/2025/06/02/blob/image-20250602141449235.webp&#34; class title=&#34;要注意了,先把之前美国的地点取消勾选,才能选香港的&#34;&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;打开你的 Github&lt;img loading=&#34;lazy&#34; data-src=&#34;/2025/06/02/blob/image-20250602141723021.webp&#34; class title=&#34;点开.env.example&#34;&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;打开文件 &lt;strong&gt;.env.example&lt;/strong&gt;，将复制的内容粘贴到末尾，格式如下：&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;figcaption data-lang=&#34;plaintext&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;BLOB_READ_WRITE_TOKEN=vercel_blob_rw_*******************************&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;ol start=&#34;9&#34;&gt;
&lt;li&gt;
&lt;p&gt;打开 &lt;strong&gt;[Main Blob Storage] / app / page.tsx&lt;/strong&gt;，修改里面的内容为中文（建议保留原站链接），可参考我的配置&lt;/p&gt;
&lt;figure class=&#34;highlight tsx&#34;&gt;&lt;figcaption data-lang=&#34;React TSX&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; Image &lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;next/image&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; Link &lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;next/link&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; ExpandingArrow &lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;@/components/expanding-arrow&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;4&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; Uploader &lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;@/components/uploader&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;5&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;import&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt; Toaster &lt;span class=&#34;token punctuation&#34;&gt;&amp;#125;&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;from&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;@/components/toaster&#39;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;6&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;7&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;export&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;default&lt;/span&gt; &lt;span class=&#34;token keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;token function&#34;&gt;Home&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;&amp;#123;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;8&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;  &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;9&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;    &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;main&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;className&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;relative flex min-h-screen flex-col items-center justify-center&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token plain-text&#34;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;10&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;Toaster&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token plain-text&#34;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;11&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;Link&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;12&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token attr-name&#34;&gt;href&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;https://vercel.com/templates/next.js/blob-starter&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;13&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token attr-name&#34;&gt;className&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;group mt-20 sm:mt-0 rounded-full flex space-x-1 bg-white/30 shadow-sm ring-1 ring-gray-900/5 text-gray-600 text-sm font-medium px-10 py-2 hover:shadow-lg active:shadow-sm transition-all&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;14&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;span class=&#34;token plain-text&#34;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;15&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;p&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token plain-text&#34;&gt;可自改内容这是一个横幅&lt;/span&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;p&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token plain-text&#34;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;16&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;ExpandingArrow&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token plain-text&#34;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;17&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;Link&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token plain-text&#34;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;18&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;h1&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;className&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;pt-4 pb-8 bg-gradient-to-br from-black via-[#171717] to-[#575757] bg-clip-text text-center text-4xl font-medium tracking-tight text-transparent md:text-7xl&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token plain-text&#34;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;19&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        可自改这是大标题&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;20&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;/&lt;/span&gt;h1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token plain-text&#34;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;21&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;      &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;div&lt;/span&gt; &lt;span class=&#34;token attr-name&#34;&gt;className&lt;/span&gt;&lt;span class=&#34;token attr-value&#34;&gt;&lt;span class=&#34;token punctuation attr-equals&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;bg-white/30 p-12 shadow-xl ring-1 ring-gray-900/5 rounded-lg backdrop-blur-lg max-w-xl mx-auto w-full&lt;span class=&#34;token punctuation&#34;&gt;&#34;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;token plain-text&#34;&gt;&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;22&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token tag&#34;&gt;&lt;span class=&#34;token punctuation&#34;&gt;&amp;lt;&lt;/span&gt;&lt;span class=&#34;token class-name&#34;&gt;Uploader&lt;/span&gt;&lt;/span&gt; &lt;span class=&#34;token punctuation&#34;&gt;/&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class